import { useEffect, useRef, useState } from 'react';

export const useChatScroll = (isOpen: boolean, msgsLength: number, currentUserId?: string, lastMsgSessionId?: string) => {
  const chatContainer = useRef<HTMLDivElement>(null);
  const [isAtBottom, setIsAtBottom] = useState(true);
  const [showScrollButton, setShowScrollButton] = useState(false);
  const [unreads, setUnreads] = useState(0);

  // Use ref to track isAtBottom for the effect without adding it to deps
  const isAtBottomRef = useRef(isAtBottom);
  useEffect(() => { isAtBottomRef.current = isAtBottom; }, [isAtBottom]);

  const scrollToBottom = (smooth = true) => {
    if (!chatContainer.current) return;
    const viewport = chatContainer.current.querySelector('[data-radix-scroll-area-viewport]') as HTMLElement;
    if (viewport) {
      viewport.scrollTo({
        top: viewport.scrollHeight,
        behavior: smooth ? 'smooth' : 'auto'
      });
      setUnreads(0);
      setShowScrollButton(false);
    }
  };

  // Initial scroll to bottom
  useEffect(() => {
    if (isOpen) {
      // Small timeout to ensure content is rendered
      setTimeout(() => scrollToBottom(false), 100);
    }
  }, [isOpen]);

  // Handle scroll events
  useEffect(() => {
    const container = chatContainer.current;
    if (!container) return;

    const viewport = container.querySelector('[data-radix-scroll-area-viewport]') as HTMLElement;
    if (!viewport) return;

    const handleScroll = () => {
      const { scrollTop, scrollHeight, clientHeight } = viewport;
      const distanceToBottom = scrollHeight - scrollTop - clientHeight;
      const atBottom = distanceToBottom < 20; // 20px threshold

      setIsAtBottom(atBottom);

      if (atBottom) {
        setUnreads(0);
        setShowScrollButton(false);
      } else {
        setShowScrollButton(true);
      }
    };

    viewport.addEventListener('scroll', handleScroll);
    return () => viewport.removeEventListener('scroll', handleScroll);
  }, [isOpen]);

  // Handle new messages
  useEffect(() => {
    if (msgsLength === 0) return;

    const isMe = lastMsgSessionId === currentUserId;

    if (isAtBottomRef.current || isMe) {
      scrollToBottom(true);
    } else {
      setUnreads(prev => prev + 1);
    }
  }, [msgsLength, currentUserId]);

  return {
    chatContainer,
    showScrollButton,
    unreads,
    scrollToBottom,
    isAtBottomRef
  };
};

"use client";
import React, { useContext, useState, useEffect, useRef } from "react";
import { Button } from "@/components/ui/button";
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover";
import { motion } from "framer-motion";

import { SocketContext } from "@/contexts/socketio";
import { Users, Users2, Hash, Settings } from "lucide-react";
import { cn } from "@/lib/utils";

import { useChatScroll } from "./hooks/use-chat-scroll";
import { useTyping } from "./hooks/use-typing";
import { useSounds } from "./hooks/use-sounds";
import { ChatMessageList } from "./components/chat-message-list";
import { ChatInput } from "./components/chat-input";
import { UserList } from "./components/user-list";
import { EditProfileModal } from "./components/edit-profile-modal";
import { THEME } from "./constants";
import { getAvatarUrl } from "@/lib/avatar";

const OnlineUsers = () => {
  const { socket, users: _users, msgs } = useContext(SocketContext);
  const users = Array.from(_users.values());
  const [showUserList, setShowUserList] = useState(false);
  const [isOpen, setIsOpen] = useState(false);
  const [isEditingProfile, setIsEditingProfile] = useState(false);

  const currentUser = users.find(u => u.socketId === socket?.id);
  const { playSendSound, playReceiveSound } = useSounds();
  const prevMsgsLength = useRef(msgs.length);

  useEffect(() => {
    if (msgs.length > prevMsgsLength.current) {
      const isSmallBatch = msgs.length - prevMsgsLength.current <= 2;
      const lastMsg = msgs[msgs.length - 1];
      let isRecent = true;
      if (lastMsg?.createdAt) {
        const msgTime = new Date(lastMsg.createdAt).getTime();
        const now = Date.now();
        // If message is older than 10 seconds, assume it's history
        if (now - msgTime > 10000) isRecent = false;
      }

      if (isSmallBatch && isRecent && lastMsg) {
        if (lastMsg.username === currentUser?.name) {
          playSendSound();
        } else {
          playReceiveSound();
        }
      }
    }
    prevMsgsLength.current = msgs.length;
  }, [msgs, playSendSound, playReceiveSound, currentUser]);

  // Use custom hooks
  const {
    chatContainer,
    showScrollButton,
    unreads,
    scrollToBottom,
    isAtBottomRef
  } = useChatScroll(
    isOpen,
    msgs.length,
    currentUser?.id,
    msgs[msgs.length - 1]?.sessionId
  );

  const {
    typingUsers,
    handleTyping,
    getTypingText
  } = useTyping(
    socket,
    currentUser,
    scrollToBottom,
    isAtBottomRef.current
  );

  const sendMessage = (msg: string) => {
    socket?.emit("msg-send", {
      content: msg,
    });
  };

  const updateProfile = ({ name, avatar, color }: { name: string; avatar: string, color?: string }) => {
    socket?.emit("update-user", {
      username: name,
      avatar,
      color
    });
    localStorage.setItem("username", name);
    localStorage.setItem("avatar", avatar);
    if (color) localStorage.setItem("color", color);
  };

  const isSingleUser = users.length <= 1;

  return (
    <>
      <Popover
        open={isOpen}
        onOpenChange={(newOpen) => {
          if (!newOpen && isEditingProfile) return;
          setIsOpen(newOpen);
          if (!newOpen) setShowUserList(false)
        }}
      >
        <PopoverTrigger asChild>
          <Button
            variant="ghost"
            className={cn(
              "mr-4 h-11 w-12 shadow-lg transition-all duration-300 z-50 p-0",
              "bg-background/20 hover:bg-background/80 backdrop-blur-sm border-2 border-white/30 rounded-lg",
              !isOpen && unreads > 0 && "animate-pulse border-green-500/50"
            )}
          >
            <div className="relative flex items-center justify-center w-full h-full">
              <div className="relative">
                <motion.div
                  initial={{ scale: 0.5, opacity: 1 }}
                  animate={{ scale: [0.1, 2], opacity: [1, 0] }}
                  transition={{
                    duration: .4,
                    delay: 0,
                    ease: "easeOut",
                    repeat: Infinity,
                    repeatDelay: 2,
                  }}
                  className={cn("absolute -inset-1 rounded-full", unreads > 0 ? "bg-green-500/40" : "bg-transparent")}
                />
                <Users2 className="w-6 h-6" />
              </div>

              <span className={cn(
                "absolute -top-1 -right-1 flex h-5 w-5 items-center justify-center rounded-full text-[10px] font-bold transition-colors",
                unreads > 0 ? "bg-green-500 text-white" : "bg-red-500 text-white"
              )}>
                {unreads > 0 ? unreads : users.length}
              </span>
            </div>
          </Button>
        </PopoverTrigger>
        <PopoverContent
          className={cn(
            "w-80 min-h-[400px] sm:w-96 p-0 border-none shadow-2xl overflow-hidden rounded-xl mr-4 mb-4 flex flex-col",
            THEME.bg.primary,
            THEME.text.primary
          )}
          side="top"
        >
          {/* Header */}
          <div className={cn("h-12 flex items-center justify-between px-4 shadow-sm border-b shrink-0", THEME.bg.secondary, THEME.border.primary)}>
            <div className={cn("flex items-center gap-2 font-semibold", THEME.text.header)}>
              <Hash className={cn("w-5 h-5", THEME.text.secondary)} />
              <span>general</span>
            </div>
            <div className="flex items-center gap-2">
              {currentUser && (
                <Button
                  variant="ghost"
                  size="sm"
                  className={cn(
                    "h-9 w-9 p-0 gap-2 transition-colors rounded-full",
                    THEME.bg.hover,
                    THEME.text.secondary,
                    "hover:text-[#060607] dark:hover:text-white"
                  )}
                  onClick={() => setIsEditingProfile(true)}
                  title="Edit Profile"
                >
                  <div className="relative w-8 h-8">
                    <img
                      src={getAvatarUrl(currentUser.avatar)}
                      className="w-full h-full rounded-full ring-1 ring-black/10 dark:ring-white/10"
                      style={{ backgroundColor: currentUser.color || '#60a5fa' }}
                    />
                    <div className="absolute -bottom-1 -right-1 bg-[#5865f2] rounded-full border-2 border-[var(--bg-primary)]">
                      <Settings className="w-3 h-3 text-white" />
                    </div>
                  </div>
                </Button>
              )}

              <div className="w-[1px] h-4 bg-black/10 dark:bg-white/10 mx-0.5" />

              <Button
                variant="outline"
                size="sm"
                className={cn(
                  "transition-colors gap-2",
                  THEME.bg.hover,
                  `hover:${THEME.text.header.replace("text-", "text-")} `,
                  "hover:text-[#060607] dark:hover:text-white",
                  showUserList && cn(THEME.text.header, THEME.bg.active)
                )}
                onClick={() => setShowUserList(!showUserList)}
              >
                <div className="flex items-center gap-1">
                  <div className="w-2 h-2 bg-green-500 rounded-full" />
                  <span>
                    {users.length}
                  </span>
                </div>
                <Users className="w-5 h-5" />
              </Button>
            </div>
          </div>

          <div className={cn("relative flex flex-col flex-1", THEME.bg.primary)}>
            <ChatMessageList
              msgs={msgs}
              users={users}
              currentUser={currentUser}
              chatContainerRef={chatContainer}
              showScrollButton={showScrollButton}
              unreads={unreads}
              scrollToBottom={scrollToBottom}
              isSingleUser={isSingleUser}
              typingUsers={typingUsers}
              getTypingText={getTypingText}
            />

            <ChatInput
              onSendMessage={sendMessage}
              onTyping={handleTyping}
              placeholder="Message #general"
            />

            <UserList
              users={users}
              socket={socket}
              updateProfile={updateProfile}
              showUserList={showUserList}
              onClose={() => setShowUserList(false)}
              onEditProfile={() => setIsEditingProfile(true)}
            />
          </div>

        </PopoverContent>
      </Popover>

      {currentUser && (
        <EditProfileModal
          user={currentUser}
          isOpen={isEditingProfile}
          onClose={() => setIsEditingProfile(false)}
          updateProfile={updateProfile}
        />
      )}
    </>
  );
};

export default OnlineUsers;

"use client";
import { SocketContext, type User } from "@/contexts/socketio";
import { useMouse } from "@/hooks/use-mouse";
import { useThrottle } from "@/hooks/use-throttle";
import { getAvatarUrl } from "@/lib/avatar";
import { MousePointer2 } from "lucide-react";
import React, { useContext, useEffect, useState } from "react";

import { AnimatePresence, motion } from "framer-motion";
import { useMediaQuery } from "@/hooks/use-media-query";

// TODO: add clicking animation
// TODO: listen to socket disconnect
const RemoteCursors = () => {
  const { socket, users: _users, setUsers } = useContext(SocketContext);
  const isMobile = useMediaQuery("(max-width: 768px)");
  const { x, y } = useMouse({ allowPage: true });
  useEffect(() => {
    if (typeof window === "undefined" || !socket || isMobile) return;
    socket.on("cursor-changed", (data) => {
      setUsers((prev: User[]) => {
        const newUsers = [...prev]
        const user = newUsers.find(u => u.socketId === data.socketId)
        if (user) {
          user.posX = data.pos.x;
          user.posY = data.pos.y
        } else {
          newUsers.push({
            ...data,
          });
        }
        return newUsers;
      });
    });
    socket.on("users-updated", (data: User[]) => {
      setUsers(data);
    });
    return () => {
      socket.off("cursor-changed");
    };
  }, [socket, isMobile]);
  const handleMouseMove = useThrottle((x, y) => {
    socket?.emit("cursor-change", {
      pos: { x, y },
      socketId: socket.id,
    });
  }, 200);
  useEffect(() => {
    if (isMobile) return;
    handleMouseMove(x, y);
  }, [x, y, isMobile]);
  const users = Array.from(_users.values());
  return (
    <div
      //  className="h-0 z-10 relative "
      className="absolute top-0 left-0 w-full h-full z-10 animate-fade-in pointer-events-none overflow-visible"
      style={{ minHeight: '100vh' }}
    >
      {users
        .filter((user) => user.socketId !== socket?.id)
        .map((user) => (
          <Cursor
            key={user.socketId}
            x={user.posX}
            y={user.posY}
            color={user.color}
            socketId={user.socketId}
            avatar={user.avatar}
            headerText={`${user.location} ${user.flag}`}
          />
        ))}
    </div>
  );
};

const Cursor = ({
  color,
  x,
  y,
  headerText,
  socketId,
  avatar,
}: {
  x: number;
  y: number;
  color?: string;
  headerText: string;
  socketId: string;
  avatar: string;
}) => {
  const [showText, setShowText] = useState(false);
  const [msgText, setMsgText] = useState("");
  const { msgs, users } = useContext(SocketContext);

  useEffect(() => {
    setShowText(true);
    const fadeOutTimeout = setTimeout(() => {
      setShowText(false);
    }, 3000); // 1 second

    return () => {
      clearTimeout(fadeOutTimeout);
    };
  }, [x, y, msgText]);


  useEffect(() => {
    const lastMsgSessionId = msgs.at(-1)?.sessionId;
    const cursorUserId = users.find(u => u.socketId === socketId)?.id;
    if (lastMsgSessionId === cursorUserId) {
      const lastMsgContent = msgs.at(-1)?.content || "";
      const textSlice =
        lastMsgContent.slice(0, 30) + (lastMsgContent.length > 30 ? "..." : "");
      const timeToRead = Math.max(4000, Math.max(textSlice.length * 100, 1000));
      setMsgText(textSlice);
      // setShowText(true);
      const t = setTimeout(() => {
        setMsgText("");
        clearTimeout(t);
        // setShowText(false);
      }, timeToRead);
    }
  }, [msgs]);

  return (
    <motion.div
      animate={{
        x: x,
        y: y,
      }}
      className="w-6 h-6 pointer-events-auto"
      transition={{
        duration: 0.2, // Adjust duration for smoothness
        ease: "easeOut", // Choose an easing function
      }}
      onMouseEnter={() => setShowText(true)}
      onMouseLeave={() => setShowText(false)}
    >
      {/* Cursor pointer */}
      <MousePointer2
        className="w-6 h-6 z-[9999999] absolute top-0 left-0"
        style={{ color: color }}
        strokeWidth={7.2}
      />

      {/* Avatar pill that expands to show text */}
      <motion.div
